using Ledgerly.Domain.Entities; using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders; namespace Ledgerly.Infrastructure.Persistence.Configurations; public sealed class BillConfiguration:IEntityTypeConfiguration<Bill>{ public void Configure(EntityTypeBuilder<Bill> b){ b.ToTable("bills"); b.HasKey(x=>x.Id); b.HasMany(x=>x.Lines).WithOne().HasForeignKey(l=>l.BillId).OnDelete(DeleteBehavior.Cascade); b.Navigation(x=>x.Lines).UsePropertyAccessMode(PropertyAccessMode.Field);} } public sealed class BillLineConfiguration:IEntityTypeConfiguration<BillLine>{ public void Configure(EntityTypeBuilder<BillLine> b){ b.ToTable("bill_lines"); b.HasKey(x=>x.Id);} } public sealed class ExpenseConfiguration:IEntityTypeConfiguration<Expense>{ public void Configure(EntityTypeBuilder<Expense> b){ b.ToTable("expenses"); b.HasKey(x=>x.Id); b.Property(x=>x.Description).HasMaxLength(512).IsRequired(); b.Property(x=>x.ReceiptUrl).HasMaxLength(2048);} }
